import 'dart:typed_data';

import 'package:vector_math/vector_math.dart' show Vector2;

import 'cpu_formulas.dart';
import 'cpu_viewport_mapping.dart';

/// Message used to request a CPU frame render from an isolate.
final class CpuRenderRequest {
  const CpuRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.width,
    required this.height,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;
  final int width;
  final int height;
  final int sampleCount;
}

final class CpuRenderResponse {
  const CpuRenderResponse({
    required this.rgba,
    required this.width,
    required this.height,
  });

  /// RGBA8888 bytes.
  final Uint8List rgba;
  final int width;
  final int height;
}

/// Top-level entrypoint suitable for [Isolate.run].
CpuRenderResponse renderCpuFrameInIsolate(CpuRenderRequest req) {
  final bytes = _renderRect(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    // Full viewport
    fullWidth: req.width,
    fullHeight: req.height,
    // Tile == full
    x0: 0,
    y0: 0,
    w: req.width,
    h: req.height,
    sampleCount: req.sampleCount,
  );
  return CpuRenderResponse(rgba: bytes, width: req.width, height: req.height);
}

final class CpuTileRenderRequest {
  const CpuTileRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;
  final int sampleCount;
}

final class CpuTileRenderResponse {
  const CpuTileRenderResponse({
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.rgba,
  });

  final int x0;
  final int y0;
  final int w;
  final int h;
  final Uint8List rgba;
}

final class CpuViewportCoordinate {
  const CpuViewportCoordinate(this.x, this.y);

  final double x;
  final double y;
}

/// Explicit bounds contract for a CPU render tile inside a full viewport.
final class CpuRenderRect {
  const CpuRenderRect({
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
  });

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;

  void validate() {
    if (fullWidth <= 0 || fullHeight <= 0) {
      throw ArgumentError.value(
        (fullWidth, fullHeight),
        'full viewport',
        'must be positive',
      );
    }
    if (w <= 0 || h <= 0) {
      throw ArgumentError.value((w, h), 'tile size', 'must be positive');
    }
    if (x0 < 0 || y0 < 0 || x0 + w > fullWidth || y0 + h > fullHeight) {
      throw ArgumentError.value(
        (x0, y0, w, h),
        'tile rect',
        'must be within the full viewport',
      );
    }
  }
}

/// Maps a pixel sample to the CPU fractal plane.
///
/// [sampleOffsetX] and [sampleOffsetY] are normalized offsets within the pixel
/// (0.5 means pixel center). Dividing by the full dimensions keeps one-pixel
/// renders centered on pan and keeps opposite edge pixel centers symmetric.
CpuViewportCoordinate cpuViewportCoordinateForSample({
  required double panX,
  required double panY,
  required double zoom,
  required int fullWidth,
  required int fullHeight,
  required int x,
  required int y,
  required double sampleOffsetX,
  required double sampleOffsetY,
}) {
  assert(fullWidth > 0, 'fullWidth must be positive');
  assert(fullHeight > 0, 'fullHeight must be positive');
  assert(x >= 0 && x < fullWidth, 'x must be inside the full viewport');
  assert(y >= 0 && y < fullHeight, 'y must be inside the full viewport');

  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );
  final nx = viewport.normalizedSampleOffset(
    pixel: x,
    extent: fullWidth,
    sampleOffset: sampleOffsetX,
  );
  final ny = viewport.normalizedSampleOffset(
    pixel: y,
    extent: fullHeight,
    sampleOffset: sampleOffsetY,
  );
  final coordinate = viewport.coordinate(nx: nx, ny: ny);

  return CpuViewportCoordinate(coordinate.$1, coordinate.$2);
}

CpuTileRenderResponse renderCpuTileInIsolate(CpuTileRenderRequest req) {
  final bytes = _renderRect(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    fullWidth: req.fullWidth,
    fullHeight: req.fullHeight,
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    sampleCount: req.sampleCount,
  );

  return CpuTileRenderResponse(
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    rgba: bytes,
  );
}

Uint8List _renderRect({
  required String moduleId,
  required double panX,
  required double panY,
  required double zoom,
  required int iterations,
  required double bailout,
  required double juliaCX,
  required double juliaCY,
  required int fullWidth,
  required int fullHeight,
  required int x0,
  required int y0,
  required int w,
  required int h,
  required int sampleCount,
}) {
  CpuRenderRect(
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x0: x0,
    y0: y0,
    w: w,
    h: h,
  ).validate();

  final bytes = Uint8List(w * h * 4);
  final sampleGrid = CpuSampleGrid.fromRequestedCount(sampleCount);

  final juliaC = Vector2(juliaCX, juliaCY);
  final formula = cpuFormulaForModuleId(moduleId);
  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );

  for (int ty = 0; ty < h; ty++) {
    final y = y0 + ty;
    for (int tx = 0; tx < w; tx++) {
      final x = x0 + tx;

      double rAcc = 0;
      double gAcc = 0;
      double bAcc = 0;

      for (int sy = 0; sy < sampleGrid.samplesPerAxis; sy++) {
        for (int sx = 0; sx < sampleGrid.samplesPerAxis; sx++) {
          final nx = viewport.normalizedSample(
            pixel: x,
            extent: fullWidth,
            sample: sx,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final ny = viewport.normalizedSample(
            pixel: y,
            extent: fullHeight,
            sample: sy,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final coordinate = viewport.coordinate(nx: nx, ny: ny);

          final color = formula(
            coordinate.$1,
            coordinate.$2,
            iterations,
            bailout,
            juliaC,
          );
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
        }
      }

      final idx = (ty * w + tx) * 4;
      bytes[idx + 0] = (rAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 1] = (gAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 2] = (bAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 3] = 255;
    }
  }

  return bytes;
}

import 'dart:async';
import 'dart:isolate';

import 'cpu_render_isolate.dart';

/// A long-lived isolate for CPU tile rendering.
///
/// Spawning an isolate per tile (Isolate.run) is far too slow on mobile.
/// This worker keeps one isolate alive and processes tile jobs sequentially.
class CpuTileWorker {
  CpuTileWorker._(this._isolate, this._sendPort, this._sub);

  final Isolate _isolate;
  final SendPort _sendPort;
  final StreamSubscription _sub;

  static Future<CpuTileWorker> spawn() async {
    final receive = ReceivePort();
    final handshake = Completer<SendPort>();

    final sub = receive.listen((msg) {
      if (msg is SendPort && !handshake.isCompleted) {
        handshake.complete(msg);
      }
    });

    final isolate = await Isolate.spawn(_entry, receive.sendPort);
    final sendPort = await handshake.future;

    return CpuTileWorker._(isolate, sendPort, sub);
  }

  Future<CpuTileRenderResponse> renderTile(CpuTileRenderRequest req) async {
    final rp = ReceivePort();
    _sendPort.send((req, rp.sendPort));
    try {
      final msg = await rp.first;
      if (msg is CpuTileRenderResponse) return msg;
      if (msg is _CpuTileRenderFailure) throw msg.toException();
      throw StateError('Unexpected CPU tile worker reply: ${msg.runtimeType}');
    } finally {
      rp.close();
    }
  }

  void dispose() {
    _sub.cancel();
    _isolate.kill(priority: Isolate.immediate);
  }
}

/// Exception surfaced when the worker isolate could not render a requested tile.
class CpuTileWorkerException implements Exception {
  const CpuTileWorkerException({
    required this.errorType,
    required this.message,
    required this.stackTraceText,
  });

  final String errorType;
  final String message;
  final String stackTraceText;

  @override
  String toString() => 'CpuTileWorkerException($errorType): $message';
}

final class _CpuTileRenderFailure {
  const _CpuTileRenderFailure({
    required this.errorType,
    required this.message,
    required this.stackTraceText,
  });

  final String errorType;
  final String message;
  final String stackTraceText;

  factory _CpuTileRenderFailure.from(Object error, StackTrace stackTrace) {
    return _CpuTileRenderFailure(
      errorType: error.runtimeType.toString(),
      message: error.toString(),
      stackTraceText: stackTrace.toString(),
    );
  }

  CpuTileWorkerException toException() {
    return CpuTileWorkerException(
      errorType: errorType,
      message: message,
      stackTraceText: stackTraceText,
    );
  }
}

void _entry(SendPort mainSendPort) {
  final commands = ReceivePort();
  mainSendPort.send(commands.sendPort);

  commands.listen((msg) {
    SendPort? replyTo;
    try {
      final (CpuTileRenderRequest req, SendPort port) =
          msg as (CpuTileRenderRequest, SendPort);
      replyTo = port;
      final resp = renderCpuTileInIsolate(req);
      replyTo.send(resp);
    } catch (error, stackTrace) {
      replyTo?.send(_CpuTileRenderFailure.from(error, stackTrace));
    }
  });
}

import 'dart:async';

import 'package:flutter_fractals/features/renderer/cpu/cpu_render_isolate.dart';
import 'package:flutter_fractals/features/renderer/cpu/cpu_tile_worker.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CpuTileWorker', () {
    test('propagates tile render failures instead of hanging', () async {
      final worker = await CpuTileWorker.spawn();
      addTearDown(worker.dispose);

      final future = worker
          .renderTile(
            const CpuTileRenderRequest(
              moduleId: 'mandelbrot',
              panX: 0.0,
              panY: 0.0,
              zoom: 1.0,
              iterations: 32,
              bailout: 4.0,
              juliaCX: -0.8,
              juliaCY: 0.156,
              fullWidth: 4,
              fullHeight: 4,
              x0: 3,
              y0: 0,
              w: 2,
              h: 1,
              sampleCount: 1,
            ),
          )
          .timeout(
            const Duration(seconds: 1),
            onTimeout: () => throw TimeoutException(
              'CpuTileWorker.renderTile did not reply to an invalid tile',
            ),
          );

      await expectLater(
        future,
        throwsA(
          isA<CpuTileWorkerException>().having(
            (error) => error.message,
            'message',
            contains('within the full viewport'),
          ),
        ),
      );
    });
  });
}

import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

/// Replayable viewport dimensions for CPU coordinate mapping.
///
/// Render requests should provide positive dimensions. When a direct mapping
/// caller passes invalid dimensions, fall back to a square viewport instead of
/// leaking zero/negative aspect ratios into fractal coordinates.
final class CpuViewportDimensions {
  const CpuViewportDimensions({required this.width, required this.height});

  final int width;
  final int height;

  factory CpuViewportDimensions.fromSize({
    required int width,
    required int height,
  }) {
    if (width <= 0 || height <= 0) {
      return const CpuViewportDimensions(width: 1, height: 1);
    }
    return CpuViewportDimensions(width: width, height: height);
  }

  double get aspect => width / height;
}

/// Shared CPU-render viewport mapping.
///
/// Pixel coordinates are edge-inclusive for iteration buffers, preserving the
/// existing scalar-field/golden contract. Subpixel sample coordinates are
/// center-of-pixel positions and must stay inside the same [-1, 1] viewport.
final class CpuViewportMapping {
  final double centerX;
  final double centerY;
  final double scale;
  final double aspect;

  CpuViewportMapping({
    required Vector2 viewPan,
    required double viewZoom,
    required int width,
    required int height,
  }) : this.fromScalars(
          panX: viewPan.x,
          panY: viewPan.y,
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping.fromScalars({
    required double panX,
    required double panY,
    required double viewZoom,
    required int width,
    required int height,
  })  : centerX = panX,
        centerY = panY,
        scale = 1.5 / normalizeZoom(viewZoom),
        aspect = CpuViewportDimensions.fromSize(
          width: width,
          height: height,
        ).aspect;

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return 1.0;
    return zoom;
  }

  double normalizedPixel(int pixel, int extent) {
    if (extent <= 1) return 0.0;
    return (pixel / (extent - 1)) * 2.0 - 1.0;
  }

  double normalizedSample({
    required int pixel,
    required int extent,
    required int sample,
    required int samplesPerAxis,
  }) {
    final safeSamples = samplesPerAxis <= 0 ? 1 : samplesPerAxis;
    final safeSample = sample.clamp(0, safeSamples - 1).toInt();
    return normalizedSampleOffset(
      pixel: pixel,
      extent: extent,
      sampleOffset: (safeSample + 0.5) / safeSamples,
    );
  }

  double normalizedSampleOffset({
    required int pixel,
    required int extent,
    required double sampleOffset,
  }) {
    if (extent <= 1) return 0.0;
    final safePixel = pixel.clamp(0, extent - 1).toInt();
    final safeOffset =
        sampleOffset.isNaN ? 0.5 : sampleOffset.clamp(0.0, 1.0).toDouble();
    final subPixel = safePixel + safeOffset;
    return (subPixel / extent) * 2.0 - 1.0;
  }

  (double x, double y) coordinate({required double nx, required double ny}) {
    return (centerX + nx * scale * aspect, centerY + ny * scale);
  }
}

/// Replayable CPU anti-aliasing grid derived from a requested sample count.
///
/// The CPU renderer samples a square grid, so non-square requests are rounded up
/// to the next square grid instead of silently dropping requested samples.
final class CpuSampleGrid {
  CpuSampleGrid.fromRequestedCount(int requestedCount)
      : this._(
          requestedCount: requestedCount,
          samplesPerAxis: _samplesPerAxisFor(requestedCount),
        );

  const CpuSampleGrid._({
    required this.requestedCount,
    required this.samplesPerAxis,
  });

  final int requestedCount;
  final int samplesPerAxis;

  int get totalSamples => samplesPerAxis * samplesPerAxis;

  bool get wasRoundedUp => totalSamples > math.max(1, requestedCount);

  static int _samplesPerAxisFor(int requestedCount) {
    if (requestedCount <= 0) return 1;
    return math.max(1, math.sqrt(requestedCount).ceil());
  }
}

import 'dart:math' as math;

/// Replayable CPU iteration budget policy for zoom-dependent refinement.
///
/// CPU rendering has preview/refine/slow-mode entry points that must agree on
/// how a zoom sample is sanitized before adding deep-zoom iteration headroom.
/// Keeping this pure avoids timer-driven render paths depending on Dart's
/// `log(...).round()` behavior for malformed zoom values.
final class CpuIterationBudget {
  static const int minimumIterations = 50;
  static const double zoomLog2IterationStep = 32.0;

  const CpuIterationBudget._();

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return 1.0;
    return zoom;
  }

  static int forZoom({
    required int baseIterations,
    required int maxIterations,
    required double zoom,
  }) {
    final safeMaxIterations = math.max(minimumIterations, maxIterations);
    final normalizedZoom = normalizeZoom(zoom);
    final extraIterations = normalizedZoom <= 1.0
        ? 0
        : (math.log(normalizedZoom) / math.ln2 * zoomLog2IterationStep).round();

    return (baseIterations + extraIterations).clamp(
      minimumIterations,
      safeMaxIterations,
    );
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/features/renderer/cpu_formulas.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';

void main() {
  group('CPU render viewport mapping', () {
    test('keeps opposite edge pixel centers symmetric around pan', () {
      final left = cpuViewportCoordinateForSample(
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        fullWidth: 4,
        fullHeight: 2,
        x: 0,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );
      final right = cpuViewportCoordinateForSample(
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        fullWidth: 4,
        fullHeight: 2,
        x: 3,
        y: 1,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(left.x + right.x, closeTo(-1.0, 1e-12));
      expect(left.y + right.y, closeTo(0.5, 1e-12));
    });

    test('rejects tile rectangles outside the full viewport before sampling', () {
      const request = CpuTileRenderRequest(
        moduleId: 'mandelbrot',
        panX: 0.0,
        panY: 0.0,
        zoom: 1.0,
        iterations: 32,
        bailout: 4.0,
        juliaCX: -0.8,
        juliaCY: 0.156,
        fullWidth: 4,
        fullHeight: 4,
        x0: 3,
        y0: 0,
        w: 2,
        h: 1,
        sampleCount: 1,
      );

      expect(
        () => renderCpuTileInIsolate(request),
        throwsA(
          isA<ArgumentError>().having(
            (error) => error.message,
            'message',
            contains('within the full viewport'),
          ),
        ),
      );
    });

    test('maps a one-pixel frame to the requested pan center', () {
      const request = CpuRenderRequest(
        moduleId: 'mandelbrot',
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        iterations: 32,
        bailout: 4.0,
        juliaCX: -0.8,
        juliaCY: 0.156,
        width: 1,
        height: 1,
        sampleCount: 1,
      );

      final frame = renderCpuFrameInIsolate(request);
      final expected = cpuFormulaForModuleId(request.moduleId)(
        request.panX,
        request.panY,
        request.iterations,
        request.bailout,
        Vector2(request.juliaCX, request.juliaCY),
      );

      expect(frame.rgba, hasLength(4));
      expect(frame.rgba[0], expected.$1.clamp(0, 255).round());
      expect(frame.rgba[1], expected.$2.clamp(0, 255).round());
      expect(frame.rgba[2], expected.$3.clamp(0, 255).round());
      expect(frame.rgba[3], 255);
    });
  });
}

import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';
import 'package:flutter_fractals/features/renderer/cpu_viewport_mapping.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

void main() {
  group('CPU viewport mapping', () {
    test('subpixel samples stay inside the normalized viewport', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(-0.5, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(0.5, 1e-12),
      );
    });

    test('invalid subpixel sample candidates clamp to the pixel footprint', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 4,
          samplesPerAxis: 2,
        ),
        closeTo(0.75, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: -1,
          samplesPerAxis: 2,
        ),
        closeTo(-0.75, 1e-12),
      );
    });

    test('edge pixels preserve iteration-buffer edge-inclusive contract', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(viewport.normalizedPixel(0, 2), -1.0);
      expect(viewport.normalizedPixel(1, 2), 1.0);
    });

    test('invalid zoom falls back to replayable unit-scale coordinates', () {
      for (final zoom in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        final viewport = CpuViewportMapping(
          viewPan: Vector2.zero(),
          viewZoom: zoom,
          width: 2,
          height: 2,
        );

        expect(viewport.scale, 1.5, reason: 'zoom=$zoom');
        expect(
          viewport.coordinate(nx: 0.5, ny: -0.5),
          (0.75, -0.75),
          reason: 'zoom=$zoom',
        );
      }
    });

    test('invalid viewport dimensions fall back to square aspect', () {
      expect(
        CpuViewportDimensions.fromSize(width: 0, height: 2).aspect,
        1.0,
      );
      expect(
        CpuViewportDimensions.fromSize(width: 2, height: -1).aspect,
        1.0,
      );

      final zeroWidthViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 0,
        height: 2,
      );
      final negativeHeightViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: -1,
      );

      expect(zeroWidthViewport.coordinate(nx: 0.5, ny: -0.5), (0.75, -0.75));
      expect(
        negativeHeightViewport.coordinate(nx: 0.5, ny: -0.5),
        (0.75, -0.75),
      );
    });

    test('isolate sample mapping shares invalid zoom normalization', () {
      final coordinate = cpuViewportCoordinateForSample(
        panX: 0.0,
        panY: 0.0,
        zoom: double.nan,
        fullWidth: 2,
        fullHeight: 2,
        x: 1,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(coordinate.x, 0.75);
      expect(coordinate.y, -0.75);
    });

    test('anti-aliasing grid makes non-square sample counts replayable', () {
      expect(CpuSampleGrid.fromRequestedCount(-1).samplesPerAxis, 1);
      expect(CpuSampleGrid.fromRequestedCount(1).totalSamples, 1);
      expect(CpuSampleGrid.fromRequestedCount(4).totalSamples, 4);
      expect(CpuSampleGrid.fromRequestedCount(8).samplesPerAxis, 3);
      expect(CpuSampleGrid.fromRequestedCount(8).totalSamples, 9);
    });

    test('anti-aliasing grid never drops requested multisample candidates', () {
      for (final requestedCount in [2, 3, 5, 6, 7, 8]) {
        final grid = CpuSampleGrid.fromRequestedCount(requestedCount);

        expect(
          grid.totalSamples,
          greaterThanOrEqualTo(requestedCount),
          reason: 'requestedCount=$requestedCount',
        );
        expect(grid.requestedCount, requestedCount);
        expect(grid.wasRoundedUp, isTrue);
      }
    });

    test('single-pixel iteration buffer samples the viewport center', () async {
      final buffer = await renderCpuIterationBuffer(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.5, 0.0),
        viewZoom: 1.0,
        iterations: 50,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: 1,
        height: 1,
      );

      expect(buffer, isNotNull);
      expect(buffer!.single, 50);
    });
  });
}

import 'dart:async';
import 'dart:math';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/services/test_logger.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_controller_snapshots.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_effect_input_bounds.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_view_input_bounds.dart';
import 'package:flutter_fractals/core/services/runtime_mode_service.dart';
import 'package:vector_math/vector_math.dart';

/// Manages the state of fractal rendering and user interactions.
///
/// [FractalController] is the central state manager for the fractal viewer.
/// It handles:
/// - **Module selection**: Switching between fractal types
/// - **Parameter updates**: Modifying fractal settings with validation
/// - **View transformations**: Pan, zoom, and rotation
/// - **Preset management**: Applying and randomizing configurations
///
/// This controller uses [ChangeNotifier] for reactive updates and is
/// typically provided via the Provider package.
///
/// {@category State Management}
///
/// Example usage:
/// ```dart
/// final controller = FractalController(registry);
///
/// // Switch fractal type
/// controller.selectModule(registry.byId('julia'));
///
/// // Update a parameter
/// controller.updateParam('iterations', 150);
///
/// // Apply a preset
/// controller.applyPreset(myPreset);
///
/// // Reset to defaults
/// controller.resetSession();
/// ```
class FractalController extends ChangeNotifier {
  static const bool _adaptiveIterationsEnabled = bool.fromEnvironment(
    'ADAPTIVE_ITERATIONS',
    defaultValue: true,
  );
  static const int _adaptiveIterationsMinStep = 8;
  static const double _adaptiveZoomEpsilon = 1.01;

  // Test mode detection - skip timer-based animations in automated tests.
  bool get _isTest => RuntimeModeService.isAutomatedTest;

  /// The module registry containing all available fractal types.
  final ModuleRegistry registry;

  final TestLogger? _logger;
  late FractalModule _module;
  Map<String, Object> _params = {};
  FractalViewState _view = FractalViewState.initial();
  bool _transparentBackground = false;
  bool _rotationLocked = false;
  bool _glowEnabled = false;
  double _glowSigma = 1.0; // blur radius multiplier: 1.0 = standard
  double _glowIntensity = 0.35; // opacity of glow layer

  // Animation state
  bool _isMorphing = false;
  double _morphProgress = 1.0;
  String? _previousModuleId;
  Timer? _morphTimer;
  bool _isCelebrating = false;
  Timer? _celebrationTimer;

  // Interesting spot tracking for celebrations
  int _consecutiveInterestingSpots = 0;
  DateTime? _lastInterestingSpotTime;
  final _celebrationController = StreamController<void>.broadcast();
  double _lastAdaptiveZoom = 1.0;

  /// Creates a new [FractalController] with the given [registry].
  ///
  /// Optionally accepts a [logger] for test instrumentation.
  /// Initializes with the first module in the registry.
  FractalController(this.registry, {TestLogger? logger}) : _logger = logger {
    _module = registry.modules.first;
    _applyPreset(_module.defaultPreset);
    _lastAdaptiveZoom = _view.zoom;
  }

  /// Whether a module morph transition is in progress.
  bool get isMorphing => _isMorphing;

  /// Progress of the current morph transition (0.0 to 1.0).
  double get morphProgress => _morphProgress;

  /// The previous module ID during a morph transition.
  String? get previousModuleId => _previousModuleId;

  /// Whether a celebration effect should be shown.
  bool get isCelebrating => _isCelebrating;

  /// Stream that emits when a celebration should be triggered.
  Stream<void> get onCelebration => _celebrationController.stream;

  /// The currently selected fractal module.
  ///
  /// Determines which fractal type is being rendered and
  /// what parameters are available.
  FractalModule get module => _module;

  /// Current parameter values keyed by parameter ID.
  ///
  /// These are passed to the shader each frame via [FractalRenderState].
  /// Public reads receive a read-only snapshot; use [updateParam] to mutate.
  Map<String, Object> get params => snapshotFractalControllerParams(_params);

  /// Current view state (pan, zoom, rotation).
  ///
  /// Updated by gesture handlers and preset application.
  /// Public reads receive cloned vectors; use view update methods to mutate.
  FractalViewState get view => snapshotFractalControllerView(_view);

  /// Whether the fractal should render with a transparent background.
  ///
  /// Used for transparent PNG export.
  bool get transparentBackground => _transparentBackground;

  /// Whether gesture-based rotation is locked.
  bool get rotationLocked => _rotationLocked;

  bool get glowEnabled => _glowEnabled;
  double get glowSigma => _glowSigma;
  double get glowIntensity => _glowIntensity;

  // Kaleidoscope state
  bool _kaleidoscopeEnabled = false;
  int _kaleidoscopeSectors = 8;
  bool _kaleidoscopeMirror = true;
  double _kaleidoscopeRotation = 0.0;
  int _kaleidoscopeMirrorMode =
      0; // 0=alternado, 1=doble, 2=triple, 3=sin espejo

  bool get kaleidoscopeEnabled => _kaleidoscopeEnabled;
  int get kaleidoscopeSectors => _kaleidoscopeSectors;
  bool get kaleidoscopeMirror => _kaleidoscopeMirror;
  double get kaleidoscopeRotation => _kaleidoscopeRotation;
  int get kaleidoscopeMirrorMode => _kaleidoscopeMirrorMode;

  void setKaleidoscopeEnabled(bool enabled) {
    // Force enabled for kaleidoscope modules
    if (_module.id.contains('kaleidoscope')) {
      enabled = true;
    }
    if (_kaleidoscopeEnabled != enabled) {
      _kaleidoscopeEnabled = enabled;
      notifyListeners();
    }
  }

  void setKaleidoscopeSectors(int sectors) {
    final clamped = sectors.clamp(4, 16);
    if (_kaleidoscopeSectors != clamped) {
      _kaleidoscopeSectors = clamped;
      notifyListeners();
    }
  }

  void setKaleidoscopeMirror(bool mirror) {
    if (_kaleidoscopeMirror != mirror) {
      _kaleidoscopeMirror = mirror;
      notifyListeners();
    }
  }

  void setKaleidoscopeMirrorMode(int mode) {
    final clamped = mode.clamp(0, 3);
    if (_kaleidoscopeMirrorMode != clamped) {
      _kaleidoscopeMirrorMode = clamped;
      notifyListeners();
    }
  }

  void setKaleidoscopeRotation(double rotation) {
    final normalized = FractalEffectInputBounds.normalizeKaleidoscopeRotation(
      candidate: rotation,
      current: _kaleidoscopeRotation,
    );
    if (_kaleidoscopeRotation != normalized) {
      _kaleidoscopeRotation = normalized;
      notifyListeners();
    }
  }

  /// Switches to a different fractal module.
  ///
  /// The [module] must be a valid module from the registry.
  /// Applies the module's default preset after switching.
  /// Triggers a smooth morph transition animation.
  ///
  /// No-op if [module] is already the current module.
  void selectModule(FractalModule module, {bool animate = true}) {
    if (_module.id == module.id) {
      return;
    }

    final previousId = _module.id;
    _module = module;
    _applyPreset(module.defaultPreset);

    if (animate) {
      _startMorphTransition(previousId);
    }

    // Auto-enable kaleidoscope effect for these modules with specific defaults
    if (module.id.contains('kaleidoscope')) {
      _kaleidoscopeEnabled = true;
      _kaleidoscopeSectors = 16;
      _kaleidoscopeMirrorMode = 3; // "Sin" espejo
    }

    notifyListeners();
    _logChange('stateChange', 'moduleSwitch', 'Switched to ${module.id}');
  }

  /// Starts a morph transition animation between fractal types.
  void _startMorphTransition(String fromModuleId) {
    // Skip timer-based animations in test mode
    if (_isTest) {
      _morphProgress = 1.0;
      _isMorphing = false;
      return;
    }

    _previousModuleId = fromModuleId;
    _isMorphing = true;
    _morphProgress = 0.0;

    HapticFeedback.lightImpact();

    _morphTimer?.cancel();

    const duration = Duration(milliseconds: 600);
    const fps = 60;
    final steps = (duration.inMilliseconds / (1000 / fps)).round();
    var step = 0;

    _morphTimer = Timer.periodic(
      Duration(milliseconds: 1000 ~/ fps),
      (timer) {
        step++;
        // Use ease-out cubic curve
        final t = step / steps;
        _morphProgress = 1.0 - pow(1.0 - t, 3);
        notifyListeners();

        if (step >= steps) {
          timer.cancel();
          _morphProgress = 1.0;
          _isMorphing = false;
          _previousModuleId = null;
          notifyListeners();
        }
      },
    );
  }

  /// Updates a single fractal parameter.
  ///
  /// The [id] must match a parameter defined in the current module.
  /// The [value] is automatically clamped to the parameter's valid range.
  ///
  /// Example:
  /// ```dart
  /// controller.updateParam('iterations', 200);
  /// controller.updateParam('colorScheme', 2);
  /// ```
  void updateParam(String id, Object value) {
    final schema = _findParam(id);
    if (schema == null) return;
    _params = Map<String, Object>.from(_params);
    _params[id] = normalizeFractalParamValue(schema, value);
    notifyListeners();
    _logChange('stateChange', 'paramUpdate', 'Updated $id',
        metadata: {'value': value.toString()});
  }

  /// Applies a preset, setting all parameters and view state.
  ///
  /// The [preset] should match the current module (by moduleId).
  /// Missing parameters are filled with module defaults.
  void applyPreset(FractalPreset preset) {
    _applyPreset(preset);
    notifyListeners();
    _logChange('stateChange', 'presetApply', 'Applied preset ${preset.name}');
  }

  /// Resets all parameters to the module's default values.
  ///
  /// Does not affect the view state (pan, zoom, rotation).
  void resetParams() {
    _params = _normalizedParamsForPreset(_module.defaultPreset);
    notifyListeners();
    _logChange('stateChange', 'reset', 'Reset params to default');
  }

  /// Resets the view state to initial values.
  ///
  /// Sets zoom to 1.0, pan to center, and rotation to zero.
  /// Does not affect fractal parameters.
  void resetView() {
    _view = FractalViewState.initial();
    _lastAdaptiveZoom = _view.zoom;
    notifyListeners();
    _logChange('stateChange', 'reset', 'Reset view');
  }

  /// Resets the entire session state.
  ///
  /// Restores parameters to defaults, resets view state,
  /// and disables transparent background. The selected module
  /// remains unchanged.
  void resetSession() {
    // Reset params to module defaults, but reset the view to the true "initial" view.
    // (Module default presets may intentionally start at a non-zero pan like -0.5,0.0 for Mandelbrot.)
    _applyPreset(_module.defaultPreset);
    _view = FractalViewState.initial();
    _lastAdaptiveZoom = _view.zoom;
    _transparentBackground = false;
    _rotationLocked = false;
    notifyListeners();
    _logChange('stateChange', 'reset', 'Reset session');
  }

  /// Randomizes all parameters within their valid ranges.
  ///
  /// Creates interesting, unpredictable fractal configurations.
  /// Useful for exploration and discovery.
  void randomizeParams() {
    final random = Random();
    final updated = <String, Object>{};
    for (final param in _module.parameters) {
      switch (param.type) {
        case FractalParamType.float:
          final raw = param.min + random.nextDouble() * (param.max - param.min);
          final stepped = _roundToStep(raw, param.step);
          updated[param.id] = stepped;
          break;
        case FractalParamType.integer:
          final value =
              param.min + random.nextInt((param.max - param.min).round() + 1);
          updated[param.id] = value.round();
          break;
        case FractalParamType.enumeration:
          if (param.options.isNotEmpty) {
            final choice = param.options[random.nextInt(param.options.length)];
            updated[param.id] = choice.value;
          } else {
            updated[param.id] = param.defaultValue;
          }
          break;
        case FractalParamType.boolean:
          updated[param.id] = random.nextBool();
          break;
      }
    }
    _params = updated;
    notifyListeners();
    _logChange(
        'stateChange', 'randomize', 'Randomized params for ${_module.id}');
  }

  /// Updates the zoom level.
  ///
  /// The [zoom] value is clamped to range [moduleMinZoom, 1e12] to support
  /// deep-zoom exploration before precision fallback kicks in.
  void updateZoom(double zoom) {
    final clampedZoom = FractalViewInputBounds.normalizeZoom(
      candidate: zoom,
      currentZoom: _view.zoom,
      moduleId: _module.id,
    );
    final zoomingIn = clampedZoom > (_lastAdaptiveZoom * _adaptiveZoomEpsilon);
    _view = _view.copyWith(zoom: clampedZoom);
    _lastAdaptiveZoom = clampedZoom;

    final autoIterations = _applyAdaptiveIterationsForZoom(
      zoom: clampedZoom,
      zoomingIn: zoomingIn,
    );

    notifyListeners();
    _logChange('userAction', 'zoom', 'Zoom updated', metadata: {
      'zoom': clampedZoom,
      if (autoIterations != null) 'autoIterations': autoIterations,
    });
  }

  /// Updates the 2D pan offset.
  ///
  /// Each component of [pan] is clamped to range [-3.0, 3.0].
  /// Used for 2D fractals to navigate the complex plane.
  void updatePan(Vector2 pan) {
    _view = _view.copyWith(
      pan: Vector2(
        FractalViewInputBounds.normalizePanComponent(
          candidate: pan.x,
          current: _view.pan.x,
        ),
        FractalViewInputBounds.normalizePanComponent(
          candidate: pan.y,
          current: _view.pan.y,
        ),
      ),
    );
    notifyListeners();
    _logChange('userAction', 'pan', 'Pan updated',
        metadata: {'x': pan.x, 'y': pan.y});
  }

  /// Updates the 3D rotation angles.
  ///
  /// Used for 3D fractals like Mandelbulb to control camera orientation.
  void updateRotation(Vector3 rotation) {
    _view = _view.copyWith(
      rotation: FractalViewInputBounds.normalizeRotation(
        candidate: rotation,
        current: _view.rotation,
      ),
    );
    notifyListeners();
  }

  /// Locks or unlocks gesture-based rotation.
  void setRotationLocked(bool value) {
    if (_rotationLocked == value) return;
    _rotationLocked = value;
    notifyListeners();
    _logChange(
      'stateChange',
      'rotationLock',
      value ? 'Rotation locked' : 'Rotation unlocked',
    );
  }

  /// Toggles gesture-based rotation lock.
  void toggleRotationLock() {
    setRotationLocked(!_rotationLocked);
  }

  void setGlowEnabled(bool value) {
    if (_glowEnabled == value) return;
    _glowEnabled = value;
    notifyListeners();
  }

  void setGlowSigma(double value) {
    _glowSigma = FractalEffectInputBounds.normalizeGlowSigma(
      candidate: value,
      current: _glowSigma,
    );
    notifyListeners();
  }

  void setGlowIntensity(double value) {
    _glowIntensity = FractalEffectInputBounds.normalizeGlowIntensity(
      candidate: value,
      current: _glowIntensity,
    );
    notifyListeners();
  }

  /// Sets whether the background should be transparent.
  ///
  /// When [value] is true, the shader renders background pixels
  /// with alpha=0, suitable for transparent PNG export.
  void setTransparentBackground(bool value) {
    _transparentBackground = value;
    notifyListeners();
  }

  void _logChange(String type, String category, String message,
      {Map<String, dynamic>? metadata}) {
    _logger?.log(LogEvent(
      timestamp: DateTime.now(),
      type: type,
      category: category,
      message: message,
      metadata: metadata,
    ));
  }

  /// Records finding an interesting spot in the fractal.
  ///
  /// When multiple interesting spots are found in quick succession,
  /// triggers a celebration effect.
  void recordInterestingSpot() {
    final now = DateTime.now();

    if (_lastInterestingSpotTime != null) {
      final elapsed = now.difference(_lastInterestingSpotTime!);
      if (elapsed.inSeconds < 30) {
        _consecutiveInterestingSpots++;

        // Trigger celebration after finding 3 interesting spots quickly
        if (_consecutiveInterestingSpots >= 3) {
          celebrate();
          _consecutiveInterestingSpots = 0;
        }
      } else {
        _consecutiveInterestingSpots = 1;
      }
    } else {
      _consecutiveInterestingSpots = 1;
    }

    _lastInterestingSpotTime = now;
    _logChange('userAction', 'discovery', 'Found interesting spot');
  }

  /// Manually triggers a celebration effect.
  void celebrate() {
    if (_isCelebrating) return;

    _isCelebrating = true;
    if (!_isTest) {
      HapticFeedback.mediumImpact();
    }
    _celebrationController.add(null);
    notifyListeners();

    // Skip timer in test mode
    if (_isTest) {
      _isCelebrating = false;
      return;
    }

    _celebrationTimer?.cancel();
    _celebrationTimer = Timer(const Duration(milliseconds: 2500), () {
      _isCelebrating = false;
      notifyListeners();
    });

    _logChange('event', 'celebration', 'Celebration triggered');
  }

  @override
  void dispose() {
    _morphTimer?.cancel();
    _celebrationTimer?.cancel();
    _celebrationController.close();
    super.dispose();
  }

  void _applyPreset(FractalPreset preset) {
    _params = _normalizedParamsForPreset(preset);
    _applyPresetView(preset.view);
  }

  Map<String, Object> _normalizedParamsForPreset(FractalPreset preset) {
    final defaults = <String, Object>{
      for (final param in _module.parameters) param.id: param.defaultValue,
    };

    final merged = {
      ...defaults,
      ...preset.params,
    };

    final clamped = <String, Object>{};
    for (final param in _module.parameters) {
      clamped[param.id] = normalizeFractalParamValue(
        param,
        merged[param.id] ?? param.defaultValue,
      );
    }
    return clamped;
  }

  void _applyPresetView(FractalViewState view) {
    _view = FractalViewInputBounds.normalizeView(
      candidate: view,
      current: _view,
      moduleId: _module.id,
    );
    _lastAdaptiveZoom = _view.zoom;
  }

  int? _applyAdaptiveIterationsForZoom({
    required double zoom,
    required bool zoomingIn,
  }) {
    if (!_adaptiveIterationsEnabled || !zoomingIn) {
      return null;
    }
    if (_module.dimension != FractalDimension.twoD) {
      return null;
    }

    final iterationsSchema = _findParam('iterations');
    if (iterationsSchema == null ||
        iterationsSchema.type != FractalParamType.integer) {
      return null;
    }

    final minIterations = iterationsSchema.min.round();
    final maxIterations = iterationsSchema.max.round();
    final currentValue = _params['iterations'];
    final currentIterations = currentValue is num
        ? currentValue.round()
        : (iterationsSchema.defaultValue as num).round();
    final baseIterations = (iterationsSchema.defaultValue as num).round();

    final targetIterations = _suggestIterationsForZoom(
      zoom: zoom,
      baseIterations: baseIterations,
      minIterations: minIterations,
      maxIterations: maxIterations,
    );
    if (targetIterations <= currentIterations) {
      return null;
    }

    final delta = targetIterations - currentIterations;
    final step = delta >= 256
        ? 64
        : delta >= 96
            ? 32
            : delta >= 32
                ? 16
                : _adaptiveIterationsMinStep;
    final nextIterations =
        (currentIterations + step).clamp(minIterations, maxIterations);
    if (nextIterations <= currentIterations) {
      return null;
    }

    _params = Map<String, Object>.from(_params);
    _params['iterations'] = nextIterations;
    _logChange(
      'stateChange',
      'adaptiveIterations',
      'Adaptive iterations increased',
      metadata: {
        'module': _module.id,
        'zoom': zoom,
        'from': currentIterations,
        'to': nextIterations,
        'target': targetIterations,
      },
    );
    return nextIterations;
  }

  int _suggestIterationsForZoom({
    required double zoom,
    required int baseIterations,
    required int minIterations,
    required int maxIterations,
  }) {
    final safeZoom = max(1.0, zoom);
    final zoomOctaves = log(safeZoom) / ln2;
    final extra = max(0, (zoomOctaves * 48.0).round());
    final raw = baseIterations + extra;
    // Snap to a small step to avoid jittery one-by-one jumps.
    final snapped = ((raw + 3) ~/ 4) * 4;
    return snapped.clamp(minIterations, maxIterations);
  }

  double _roundToStep(double value, double step) {
    if (step <= 0) {
      return value;
    }
    final snapped = (value / step).round() * step;
    // Avoid floating point noise for typical slider steps.
    return double.parse(snapped.toStringAsFixed(6));
  }

  FractalParameter? _findParam(String id) {
    for (final param in _module.parameters) {
      if (param.id == id) {
        return param;
      }
    }
    return null;
  }

  /// Alias for [view] for backward compatibility.
  FractalViewState get viewState => view;

  /// The currently selected fractal module (alias for [module]).
  FractalModule get currentModule => _module;

  /// Loads a complete state from another controller or snapshot.
  ///
  /// This initializes the controller from a full state including
  /// module, parameters, view state, and transparency setting.
  /// Parameters are clamped to the target module's schema.
  ///
  /// Can accept either a [module] object directly or a [moduleId] string.
  void loadState({
    FractalModule? module,
    String? moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
    bool transparentBackground = false,
    bool animateModule = false,
  }) {
    // Find the module by ID or use provided module
    final FractalModule targetModule;
    if (module != null) {
      targetModule = module;
    } else if (moduleId != null) {
      targetModule = registry.modules.firstWhere(
        (m) => m.id == moduleId,
        orElse: () => _module,
      );
    } else {
      targetModule = _module;
    }

    // Switch to the target module
    if (targetModule.id != _module.id) {
      if (animateModule) {
        selectModule(targetModule, animate: true);
      } else {
        _module = targetModule;
      }
    }

    // Auto-enable kaleidoscope effect for these modules with specific defaults
    if (_module.id.contains('kaleidoscope')) {
      _kaleidoscopeEnabled = true;
      _kaleidoscopeSectors = 16;
      _kaleidoscopeMirrorMode = 3; // "Sin" espejo
    }

    // Apply parameters with clamping
    final clamped = <String, Object>{};
    for (final param in _module.parameters) {
      final value = params[param.id] ?? param.defaultValue;
      clamped[param.id] = normalizeFractalParamValue(param, value);
    }
    _params = clamped;

    // Set view state
    _view = FractalViewInputBounds.normalizeView(
      candidate: view,
      current: _view,
      moduleId: _module.id,
    );
    _lastAdaptiveZoom = _view.zoom;

    // Set transparency
    _transparentBackground = transparentBackground;

    notifyListeners();
    _logChange('stateChange', 'loadState', 'Loaded state for ${_module.id}');
  }
}

/// Pure bounds for effect inputs accepted by [FractalController].
///
/// Glow values are bounded shader-control inputs: finite values and infinities
/// clamp to explicit UI limits, while NaN falls back to the last known-good
/// value instead of being promoted to a maximum by [double.clamp].
/// Kaleidoscope rotation is intentionally unbounded, but shader uniforms still
/// need finite angles, so non-finite candidates preserve the last finite angle.
final class FractalEffectInputBounds {
  static const double minGlowSigma = 0.1;
  static const double maxGlowSigma = 5.0;
  static const double minGlowIntensity = 0.0;
  static const double maxGlowIntensity = 1.0;

  const FractalEffectInputBounds._();

  static double normalizeGlowSigma({
    required double candidate,
    required double current,
  }) {
    return _normalizeBounded(
      candidate: candidate,
      current: current,
      minValue: minGlowSigma,
      maxValue: maxGlowSigma,
    );
  }

  static double normalizeGlowIntensity({
    required double candidate,
    required double current,
  }) {
    return _normalizeBounded(
      candidate: candidate,
      current: current,
      minValue: minGlowIntensity,
      maxValue: maxGlowIntensity,
    );
  }

  static double normalizeKaleidoscopeRotation({
    required double candidate,
    required double current,
  }) {
    if (candidate.isFinite) return candidate;
    return current.isFinite ? current : 0.0;
  }

  static double _normalizeBounded({
    required double candidate,
    required double current,
    required double minValue,
    required double maxValue,
  }) {
    final fallback = current.isNaN ? minValue : current;
    if (candidate.isNaN) {
      return fallback.clamp(minValue, maxValue).toDouble();
    }
    return candidate.clamp(minValue, maxValue).toDouble();
  }
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';

/// Normalizes raw parameter values against a module parameter schema.
///
/// This keeps replayed state, presets, and direct UI updates on the same
/// contract: finite numeric values clamp to schema bounds, enum values must be
/// one of the declared options, booleans must be real booleans, and non-finite
/// numeric values fall back to the schema default instead of being promoted to
/// an arbitrary bound.
Object normalizeFractalParamValue(FractalParameter schema, Object value) {
  if (schema.type == FractalParamType.boolean) {
    return value is bool ? value : _booleanDefault(schema);
  }
  if (schema.type == FractalParamType.enumeration) {
    final optionValues = schema.options.map((option) => option.value).toSet();
    return optionValues.contains(value) ? value : schema.defaultValue;
  }

  final numericValue = _finiteNumericValue(value);
  if (numericValue != null) {
    final clamped = numericValue.clamp(schema.min, schema.max);
    if (schema.type == FractalParamType.integer) {
      return clamped.round();
    }
    return clamped;
  }
  return schema.defaultValue;
}

double? _finiteNumericValue(Object value) {
  if (value is! num) return null;
  final numericValue = value.toDouble();
  return numericValue.isFinite ? numericValue : null;
}

bool _booleanDefault(FractalParameter schema) {
  final defaultValue = schema.defaultValue;
  return defaultValue is bool ? defaultValue : false;
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Pure bounds for gesture/view input accepted by FractalController.
///
/// Dart's [double.clamp] treats NaN as the upper bound. Gesture telemetry and
/// replayed state can occasionally contain NaN, and promoting that to max zoom
/// or max pan makes failures hard to replay. Preserve the last known-good value
/// for NaN while still clamping infinities to the explicit viewport limits.
/// Rotation has no explicit UI bounds, but shader uniforms still require finite
/// values; non-finite rotation components fall back to last known-good angles.
final class FractalViewInputBounds {
  static const double maxZoom = 1e12;
  static const double defaultMinZoom = 1e-9;
  static const double cantorSetMinZoom = 0.2;
  static const double minPan = -3.0;
  static const double maxPan = 3.0;

  const FractalViewInputBounds._();

  static double minZoomForModule(String moduleId) {
    switch (moduleId) {
      case 'cantor_set':
        // Prevent ultra-zoomed-out aliasing that appears as black vertical bands.
        return cantorSetMinZoom;
      default:
        return defaultMinZoom;
    }
  }

  static double normalizeZoom({
    required double candidate,
    required double currentZoom,
    required String moduleId,
  }) {
    final minZoom = minZoomForModule(moduleId);
    final fallback = currentZoom.isNaN ? minZoom : currentZoom;
    if (candidate.isNaN) return fallback.clamp(minZoom, maxZoom).toDouble();
    return candidate.clamp(minZoom, maxZoom).toDouble();
  }

  static double normalizePanComponent({
    required double candidate,
    required double current,
  }) {
    final fallback = current.isNaN ? 0.0 : current;
    if (candidate.isNaN) return fallback.clamp(minPan, maxPan).toDouble();
    return candidate.clamp(minPan, maxPan).toDouble();
  }

  static double normalizeRotationComponent({
    required double candidate,
    required double current,
  }) {
    if (candidate.isFinite) return candidate;
    return current.isFinite ? current : 0.0;
  }

  static Vector3 normalizeRotation({
    required Vector3 candidate,
    required Vector3 current,
  }) {
    return Vector3(
      normalizeRotationComponent(candidate: candidate.x, current: current.x),
      normalizeRotationComponent(candidate: candidate.y, current: current.y),
      normalizeRotationComponent(candidate: candidate.z, current: current.z),
    );
  }

  /// Sanitizes externally supplied view snapshots before they become controller
  /// state. Finite values preserve existing behavior; NaN values fall back to
  /// the last known-good view while infinities clamp to explicit bounds or, for
  /// unbounded rotation, fall back to the last known-good finite angle.
  static FractalViewState normalizeView({
    required FractalViewState candidate,
    required FractalViewState current,
    required String moduleId,
  }) {
    return candidate.copyWith(
      pan: Vector2(
        normalizePanComponent(
            candidate: candidate.pan.x, current: current.pan.x),
        normalizePanComponent(
            candidate: candidate.pan.y, current: current.pan.y),
      ),
      zoom: normalizeZoom(
        candidate: candidate.zoom,
        currentZoom: current.zoom,
        moduleId: moduleId,
      ),
      rotation: normalizeRotation(
        candidate: candidate.rotation,
        current: current.rotation,
      ),
    );
  }
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('FractalController state exposure', () {
    test('exposes params as a read-only snapshot', () {
      final controller = FractalController(ModuleRegistry());
      addTearDown(controller.dispose);

      final initialIterations = controller.params['iterations'];
      final exposedParams = controller.params;

      expect(
        () => exposedParams['iterations'] = double.nan,
        throwsUnsupportedError,
      );
      expect(controller.params['iterations'], initialIterations);
    });

    test('exposes view vectors as snapshots instead of mutable state', () {
      final controller = FractalController(ModuleRegistry());
      addTearDown(controller.dispose);

      controller.updatePan(Vector2(0.25, -0.5));
      controller.updateRotation(Vector3(0.1, 0.2, 0.3));

      final exposedView = controller.view;
      exposedView.pan.setValues(2.0, 3.0);
      exposedView.rotation.setValues(4.0, 5.0, 6.0);

      expect(controller.view.pan, Vector2(0.25, -0.5));
      expect(controller.view.rotation, Vector3(0.1, 0.2, 0.3));

      final exposedAlias = controller.viewState;
      exposedAlias.pan.setValues(-2.0, -3.0);
      exposedAlias.rotation.setValues(-4.0, -5.0, -6.0);

      expect(controller.view.pan, Vector2(0.25, -0.5));
      expect(controller.view.rotation, Vector3(0.1, 0.2, 0.3));
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Read-only snapshot of controller parameters for public exposure.
///
/// [FractalController] owns parameter validation and listener notification.
/// Returning the backing map lets callers mutate controller state without
/// normalization or notifications, so public reads get a defensive top-level
/// copy instead.
Map<String, Object> snapshotFractalControllerParams(
  Map<String, Object> params,
) {
  return Map<String, Object>.unmodifiable(params);
}

/// Defensive copy of controller view state for public exposure.
///
/// [FractalViewState] is immutable by field assignment, but its vector fields
/// are mutable. Clone vectors at the controller boundary so external reads
/// cannot mutate pan/rotation without going through controller update methods.
FractalViewState snapshotFractalControllerView(FractalViewState view) {
  return FractalViewState(
    pan: Vector2.copy(view.pan),
    zoom: view.zoom,
    rotation: Vector3.copy(view.rotation),
  );
}

import 'dart:async';
import 'package:flutter/animation.dart';
import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_runtime_state.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_zoom_planner.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';

export 'auto_explore_zoom_planner.dart'
    show AutoExploreConfig, AutoExploreSpeed;

/// Auto navigation mode that performs zoom-only cinematic movement.
///
/// Behavior:
/// - Slowly zooms in from the current zoom to a smart module-aware peak.
/// - Then zooms back out to a smart floor.
/// - Repeats continuously.
///
/// Pan is never modified by this service, so the user can pan freely.
class AutoExploreService extends ChangeNotifier {
  static const Cubic _cinematicCurve = Cubic(0.22, 0.0, 0.15, 1.0);

  final FractalController controller;
  final AutoExploreConfig config;
  late final AutoExploreZoomPlanner _zoomPlanner = AutoExploreZoomPlanner(
    config: config,
  );

  bool _isExploring = false;
  bool _isPaused = false;
  bool _pausedByUserCorrection = false;
  bool _isUserInteracting = false;
  double _speed = 1.0;

  Timer? _timer;
  Timer? _anim;

  double? _cycleBaseZoom;
  double? _lastCorrectionZoom;
  double? _interactionStartZoom;
  bool _zoomingIn = true;

  AutoExploreService({
    required this.controller,
    this.config = const AutoExploreConfig(),
  });

  bool get isExploring => _isExploring;
  bool get isPaused => _isPaused;

  /// True while user interaction temporarily takes control.
  bool get pausedByUserCorrection => _pausedByUserCorrection;

  double get speed => _speed;
  set speed(double v) {
    _speed = AutoExploreSpeed.normalize(v);
    notifyListeners();
  }

  void start() {
    if (_isExploring && !_isPaused) return;

    _isExploring = true;
    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _adoptCurrentZoomAsCycleBase();
    _zoomingIn = true;

    _scheduleNext();
    notifyListeners();
  }

  void pause() {
    if (!_isExploring) return;

    _isPaused = true;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _timer?.cancel();
    _anim?.cancel();
    notifyListeners();
  }

  void resume() {
    if (!_isExploring) {
      start();
      return;
    }

    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _adoptCurrentZoomAsCycleBase();
    _scheduleNext();
    notifyListeners();
  }

  /// Called when user starts a continuous gesture (drag/pinch).
  ///
  /// Auto movement is temporarily suspended so manual pan/zoom is never fought.
  void onUserInteractionStart() {
    if (!_isExploring || _isPaused) return;
    if (_isUserInteracting) return;

    _isUserInteracting = true;
    _pausedByUserCorrection = true;
    _interactionStartZoom = _clampZoom(controller.view.zoom);

    _timer?.cancel();
    _anim?.cancel();
    notifyListeners();
  }

  /// Called when user ends a continuous gesture.
  ///
  /// The user-selected zoom becomes the new baseline and auto mode continues.
  void onUserInteractionEnd() {
    if (!_runtimeState.canAdoptContinuousInteractionEnd) return;

    final referenceZoom = _interactionStartZoom;
    _isUserInteracting = false;
    _interactionStartZoom = null;

    _adoptUserViewAndContinue(referenceZoom: referenceZoom);
  }

  /// Called for one-shot user corrections (mouse wheel, keyboard, etc).
  void onUserCorrection() {
    if (!AutoExploreUserCorrectionPolicy.shouldAdoptOneShotCorrection(
      _runtimeState,
    )) {
      return;
    }
    _adoptUserViewAndContinue();
  }

  void _adoptUserViewAndContinue({double? referenceZoom}) {
    if (!_isExploring) return;

    final adoption = _adoptedZoom(referenceZoom: referenceZoom);
    _zoomingIn = adoption.zoomingIn;

    _cycleBaseZoom = adoption.currentZoom;
    _lastCorrectionZoom = adoption.currentZoom;
    _pausedByUserCorrection = false;

    // Restart leg planning from the user-selected zoom immediately.
    _timer?.cancel();
    _anim?.cancel();
    if (!_isPaused && !_isUserInteracting) {
      _scheduleNext();
    }

    notifyListeners();
  }

  void toggle() {
    switch (_runtimeState.toggleTransition) {
      case AutoExploreToggleTransition.start:
        return start();
      case AutoExploreToggleTransition.resume:
        return resume();
      case AutoExploreToggleTransition.pause:
        return pause();
    }
  }

  void stop() {
    _isExploring = false;
    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _timer?.cancel();
    _anim?.cancel();
    _cycleBaseZoom = null;
    _lastCorrectionZoom = null;
    _zoomingIn = true;
    notifyListeners();
  }

  double _clampZoom(double z) => _zoomPlanner.clampZoom(z);

  AutoExploreRuntimeState get _runtimeState => AutoExploreRuntimeState(
        isExploring: _isExploring,
        isPaused: _isPaused,
        isUserInteracting: _isUserInteracting,
        pausedByUserCorrection: _pausedByUserCorrection,
      );

  AutoExploreZoomAdoption _adoptedZoom({double? referenceZoom}) {
    return AutoExploreZoomAdoption.fromSamples(
      bounds: AutoExploreZoomBounds.fromConfig(config),
      currentZoom: controller.view.zoom,
      referenceZoom: referenceZoom,
      lastCorrectionZoom: _lastCorrectionZoom,
      wasZoomingIn: _zoomingIn,
    );
  }

  void _adoptCurrentZoomAsCycleBase() {
    final currentZoom = _clampZoom(controller.view.zoom);
    _cycleBaseZoom = currentZoom;
    _lastCorrectionZoom = currentZoom;
  }

  double _nextTargetZoom() {
    final current = _clampZoom(controller.view.zoom);
    _cycleBaseZoom ??= current;

    // Direction is flipped only after a leg actually reaches its target.
    // This prevents user pan interruptions from resuming in the opposite
    // direction (the reported "reverse" behavior).
    return _zoomPlanner.nextTargetZoom(
      currentZoom: current,
      cycleBaseZoom: _cycleBaseZoom,
      zoomingIn: _zoomingIn,
      moduleId: controller.module.id,
    );
  }

  void _scheduleNext() {
    _timer?.cancel();
    if (!_runtimeState.canScheduleZoomLeg) return;

    // Continuous mode: no dwell/pause between zoom-in and zoom-out legs.
    _timer = Timer(Duration.zero, () async {
      if (!_runtimeState.canScheduleZoomLeg) return;

      final targetZoom = _nextTargetZoom();
      final reachedTarget = await _animateZoomTo(targetZoom);

      if (!_runtimeState.canScheduleZoomLeg) return;
      if (reachedTarget) {
        _zoomingIn = !_zoomingIn;
      }
      _scheduleNext();
    });
  }

  Future<bool> _animateZoomTo(double targetZoom) async {
    _anim?.cancel();

    final plan = _zoomPlanner.animationPlanForZoomLeg(
      startZoom: controller.view.zoom,
      endZoom: targetZoom,
      speed: _speed,
    );
    var step = 0;

    final completer = Completer<bool>();
    _anim = Timer.periodic(plan.frameInterval, (timer) {
      if (_runtimeState.shouldInterruptAnimation) {
        timer.cancel();
        _anim = null;
        if (!completer.isCompleted) completer.complete(false);
        return;
      }

      step++;
      final progress = plan.progressForFrame(step);
      final eased = _cinematicCurve.transform(progress.raw);

      controller.updateZoom(plan.interpolate(eased));
      _lastCorrectionZoom = _clampZoom(controller.view.zoom);

      if (progress.reachedEnd) {
        timer.cancel();
        _anim = null;
        if (!completer.isCompleted) completer.complete(true);
      }
    });

    return completer.future;
  }

  @override
  void dispose() {
    stop();
    super.dispose();
  }
}

import 'dart:math';

import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

/// Auto-zoom configuration.
class AutoExploreConfig {
  static const double defaultMinZoom = 0.2;
  static const double defaultMaxZoom = 1e12;

  /// Minimum and maximum zoom targets for the auto cycle.
  final double minZoom;
  final double maxZoom;

  /// Peak zoom target starts from: baseZoom * [cycleMaxMultiplier], then gets
  /// clamped by smart precision limits per fractal module.
  final double cycleMaxMultiplier;

  /// Maximum zoom span per leg in log10 decades (e.g. 3.0 => up to 1000x).
  final double maxLegSpanDecades;

  /// Precision headroom under policy threshold to avoid probing unstable edges.
  final double precisionHeadroom;

  /// Duration for each zoom leg (in or out).
  final Duration travelDuration;

  /// Maximum multiplier for duration scaling on very large zoom spans.
  final double maxDurationScale;

  const AutoExploreConfig({
    this.minZoom = defaultMinZoom,
    this.maxZoom = defaultMaxZoom,
    this.cycleMaxMultiplier = 120.0,
    this.maxLegSpanDecades = 3.2,
    this.precisionHeadroom = 0.92,
    this.travelDuration = const Duration(milliseconds: 9000),
    this.maxDurationScale = 4.0,
  });
}

/// Speed bounds used by auto-explore playback.
///
/// Dart's [double.clamp] treats NaN as the upper bound. For playback speed,
/// invalid telemetry or UI state should fall back to neutral 1.0x instead of
/// silently selecting the fastest supported speed.
class AutoExploreSpeed {
  static const double min = 0.5;
  static const double neutral = 1.0;
  static const double max = 3.0;

  const AutoExploreSpeed._();

  static const int sliderDivisions = 25;

  static double normalize(double speed) {
    if (!speed.isFinite) return neutral;
    return speed.clamp(min, max);
  }
}

/// Relative epsilon used to ignore tiny user zoom corrections.
///
/// Values at or above 1.0 invert the lower comparison bound and make zoom-out
/// corrections undetectable. Keep normalization explicit so correction replay
/// tests can distinguish real deadbands from malformed inputs.
class AutoExploreRelativeEpsilon {
  static const double defaultValue = 1e-4;

  const AutoExploreRelativeEpsilon._();

  static double normalize(double epsilon) {
    if (!epsilon.isFinite || epsilon < 0.0 || epsilon >= 1.0) {
      return defaultValue;
    }
    return epsilon;
  }
}

/// Direction inferred from a user zoom correction.
class AutoExploreCorrectionDecision {
  static const double defaultRelativeEpsilon =
      AutoExploreRelativeEpsilon.defaultValue;

  /// Null means the correction is inside the deadband and should preserve the
  /// current auto-explore direction.
  final bool? zoomingInOverride;

  const AutoExploreCorrectionDecision._(this.zoomingInOverride);

  bool get changedDirection => zoomingInOverride != null;

  bool resolve({required bool currentZoomingIn}) =>
      zoomingInOverride ?? currentZoomingIn;

  factory AutoExploreCorrectionDecision.fromZooms({
    required double currentZoom,
    required double previousZoom,
    double relativeEpsilon = defaultRelativeEpsilon,
  }) {
    if (!_isUsableZoomSample(currentZoom) ||
        !_isUsableZoomSample(previousZoom)) {
      return const AutoExploreCorrectionDecision._(null);
    }

    final epsilon = AutoExploreRelativeEpsilon.normalize(relativeEpsilon);
    if (currentZoom > previousZoom * (1.0 + epsilon)) {
      return const AutoExploreCorrectionDecision._(true);
    }
    if (currentZoom < previousZoom * (1.0 - epsilon)) {
      return const AutoExploreCorrectionDecision._(false);
    }
    return const AutoExploreCorrectionDecision._(null);
  }

  static bool _isUsableZoomSample(double zoom) => zoom.isFinite && zoom > 0.0;
}

/// Replayable result of adopting a user-selected zoom into auto-explore.
///
/// The service stores several state fields while timers are active. Keeping the
/// zoom comparison and direction decision pure makes the hidden fallback order
/// testable: prefer the interaction-start zoom, otherwise the last correction
/// sample, otherwise the current zoom.
class AutoExploreZoomAdoption {
  final double currentZoom;
  final double previousZoom;
  final bool zoomingIn;
  final AutoExploreCorrectionDecision correctionDecision;

  const AutoExploreZoomAdoption({
    required this.currentZoom,
    required this.previousZoom,
    required this.zoomingIn,
    required this.correctionDecision,
  });

  factory AutoExploreZoomAdoption.fromSamples({
    required AutoExploreZoomBounds bounds,
    required double currentZoom,
    required double? referenceZoom,
    required double? lastCorrectionZoom,
    required bool wasZoomingIn,
  }) {
    final current = bounds.clamp(currentZoom);
    final previous = bounds.clamp(
      referenceZoom ?? lastCorrectionZoom ?? current,
    );
    final decision = AutoExploreCorrectionDecision.fromZooms(
      currentZoom: current,
      previousZoom: previous,
    );

    return AutoExploreZoomAdoption(
      currentZoom: current,
      previousZoom: previous,
      zoomingIn: decision.resolve(currentZoomingIn: wasZoomingIn),
      correctionDecision: decision,
    );
  }
}

/// Precision headroom used to keep auto-explore below renderer fallback edges.
///
/// Values above 1.0 would push candidates past the module precision threshold;
/// non-finite values must not rely on [double.clamp] because NaN clamps to the
/// upper bound and would silently promote targets to max zoom.
class AutoExplorePrecisionHeadroom {
  static const double neutral = 1.0;

  const AutoExplorePrecisionHeadroom._();

  static double normalize(double headroom) {
    if (!headroom.isFinite || headroom <= 0.0) return neutral;
    return headroom.clamp(0.0, neutral);
  }
}

/// Cycle shape used by auto-explore target planning.
///
/// Invalid multipliers or span limits can otherwise turn zoom-out floors into
/// max zooms or collapse peak candidates into NaN/minimum zooms. Keeping the
/// cycle shape explicit makes candidate planning replayable from config alone.
class AutoExploreCycleShape {
  final double cycleMaxMultiplier;
  final double maxLegSpanDecades;

  const AutoExploreCycleShape({
    required this.cycleMaxMultiplier,
    required this.maxLegSpanDecades,
  });

  factory AutoExploreCycleShape.fromConfig(AutoExploreConfig config) {
    return AutoExploreCycleShape(
      cycleMaxMultiplier: _finiteAtLeastNeutralOrDefault(
        config.cycleMaxMultiplier,
        const AutoExploreConfig().cycleMaxMultiplier,
      ),
      maxLegSpanDecades: _finiteNonNegativeOrDefault(
        config.maxLegSpanDecades,
        const AutoExploreConfig().maxLegSpanDecades,
      ),
    );
  }

  static double _finiteAtLeastNeutralOrDefault(double value, double fallback) {
    return value.isFinite && value >= 1.0 ? value : fallback;
  }

  static double _finiteNonNegativeOrDefault(double value, double fallback) {
    return value.isFinite && value >= 0.0 ? value : fallback;
  }
}

/// Duration scaling used by auto-explore zoom legs.
///
/// Invalid scale factors can otherwise flow into [double.round], where NaN or
/// infinity throws instead of producing a replayable fallback duration.
class AutoExploreDurationScale {
  static const double neutral = 1.0;

  const AutoExploreDurationScale._();

  static double normalize(double scale) {
    if (!scale.isFinite || scale < neutral) return neutral;
    return scale;
  }
}

/// Converts a zoom span into a normalized duration scale.
///
/// A leg reaches the configured maximum duration scale after this many log10
/// decades. Keeping the threshold named makes the cinematic timing assumption
/// replayable instead of burying `1.6` in duration planning.
class AutoExploreZoomSpanScale {
  static const double maxScaleSpanDecades = 1.6;

  const AutoExploreZoomSpanScale._();

  static double normalized(double spanDecades) {
    if (!spanDecades.isFinite || spanDecades <= 0.0) return 0.0;
    return (spanDecades / maxScaleSpanDecades).clamp(0.0, 1.0);
  }
}

/// Converts zoom-span scaling into a positive, finite leg duration.
///
/// This keeps duration planning replayable even when a finite-but-huge config
/// value overflows during multiplication before [double.round].
class AutoExploreLegDuration {
  // Dart Duration stores microseconds in a signed 64-bit field. Millisecond
  // candidates above this can overflow into negative durations after the
  // milliseconds-to-microseconds conversion.
  static const int _maxSafeDurationMilliseconds = 9223372036854;

  const AutoExploreLegDuration._();

  static int milliseconds({
    required Duration baseDuration,
    required double scale,
    required double speed,
  }) {
    final safeBaseMs = _safeBaseMilliseconds(baseDuration.inMilliseconds);
    if (safeBaseMs <= 0) return 1;

    final scaledMs = _finitePositiveRoundOrFallback(
      safeBaseMs * scale,
      fallback: safeBaseMs,
    );
    return max(
      1,
      _finitePositiveRoundOrFallback(
        scaledMs / AutoExploreSpeed.normalize(speed),
        fallback: safeBaseMs,
      ),
    );
  }

  static int _safeBaseMilliseconds(int baseMs) {
    if (baseMs <= 0) return 1;
    return min(baseMs, _maxSafeDurationMilliseconds);
  }

  static int _finitePositiveRoundOrFallback(
    double value, {
    required int fallback,
  }) {
    if (!value.isFinite ||
        value <= 0.0 ||
        value > _maxSafeDurationMilliseconds) {
      return fallback;
    }
    return value.round();
  }
}

/// Replayable progress for one auto-explore animation frame.
///
/// Timer-driven service code counts frames imperatively. Keeping the frame to
/// [0, 1] progress conversion pure makes off-by-one and overrun behavior
/// testable without relying on wall-clock timer order.
class AutoExploreFrameProgress {
  final int frame;
  final int totalFrames;

  const AutoExploreFrameProgress({
    required this.frame,
    required this.totalFrames,
  }) : assert(totalFrames > 0, 'totalFrames must be positive');

  double get raw {
    if (frame <= 0) return 0.0;
    return (frame / totalFrames).clamp(0.0, 1.0);
  }

  bool get reachedEnd => raw >= 1.0;
}

/// Replayable frame timing for one auto-explore zoom animation.
///
/// The service animates with a fixed frame cadence; exposing the sanitized
/// start/end zooms, duration, and frame count keeps timer-driven behavior
/// characterizable without relying on wall-clock order in service tests.
class AutoExploreFrameTiming {
  final Duration duration;
  final Duration frameInterval;

  const AutoExploreFrameTiming({
    required this.duration,
    required this.frameInterval,
  }) : assert(frameInterval > Duration.zero, 'frameInterval must be positive');

  int get totalFrames {
    final frameMicros = frameInterval.inMicroseconds;
    if (frameMicros <= 0) return 1;
    return max(1, (duration.inMicroseconds / frameMicros).round());
  }
}

