/// Represents a visited location in fractal exploration history.
///
/// Each entry captures the complete state needed to restore a viewpoint:
/// - The fractal module (type) being viewed
/// - The view state (pan, zoom, rotation)
/// - The fractal parameters at that time
/// - Optional metadata like name (for favorites) and timestamp
///
/// {@category Models}
@immutable
class HistoryEntry {
  /// Unique identifier for this history entry.
  final String id;

  /// The fractal module ID (e.g., 'mandelbrot', 'julia').
  final String moduleId;

  /// The view state (pan, zoom, rotation) at this location.
  final FractalViewState view;

  /// The fractal parameters at this location.
  final Map<String, Object> params;

  /// When this location was visited.
  final DateTime visitedAt;

  /// Optional user-defined name for favorites.
  ///
  /// If non-null, this entry is considered a favorite.
  final String? name;

  /// Whether this entry is marked as a favorite.
  bool get isFavorite => name != null;

  /// Creates a new [HistoryEntry].
  ///
  /// The supplied view vectors and parameter collections are snapshotted so a
  /// history entry remains replayable even when callers mutate their originals.
  HistoryEntry({
    required this.id,
    required this.moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
    required this.visitedAt,
    this.name,
  })  : view = snapshotHistoryView(view),
        params = snapshotHistoryParams(params);

  /// Creates a history entry from the current fractal state.
  factory HistoryEntry.fromState({
    required String moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
    String? name,
  }) {
    return HistoryEntry(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      moduleId: moduleId,
      view: view,
      params: params,
      visitedAt: DateTime.now(),
      name: name,
    );
  }

  /// Creates a copy with the given fields replaced.
  HistoryEntry copyWith({
    String? id,
    String? moduleId,
    FractalViewState? view,
    Map<String, Object>? params,
    DateTime? visitedAt,
    String? name,
    bool clearName = false,
  }) {
    return HistoryEntry(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      view: view ?? this.view,
      params: params ?? this.params,
      visitedAt: visitedAt ?? this.visitedAt,
      name: clearName ? null : (name ?? this.name),
    );
  }

  /// Serializes this entry to a JSON-compatible map.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'params': params,
      'visitedAt': visitedAt.toIso8601String(),
      'name': name,
    };
  }

  /// Deserializes a history entry from a JSON map.
  static HistoryEntry fromJson(Map<String, Object?> json) {
    final viewJson = json['view'] as Map<String, Object?>? ?? {};
    return HistoryEntry(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      view: FractalViewState(
        pan: Vector2(
          (viewJson['panX'] as num? ?? 0).toDouble(),
          (viewJson['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (viewJson['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (viewJson['rotX'] as num? ?? 0).toDouble(),
          (viewJson['rotY'] as num? ?? 0).toDouble(),
          (viewJson['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      params: (json['params'] as Map?)?.map(
            (key, value) => MapEntry(key as String, value as Object),
          ) ??
          {},
      visitedAt: DateTime.tryParse(json['visitedAt'] as String? ?? '') ??
          DateTime.now(),
      name: json['name'] as String?,
    );
  }

  /// Generates a display label for this entry.
  ///
  /// If named, returns the name. Otherwise, returns a
  /// formatted description of the location.
  String get displayLabel {
    if (name != null) return name!;
    final zoomStr = view.zoom >= 10
        ? '${view.zoom.toStringAsFixed(0)}x'
        : '${view.zoom.toStringAsFixed(1)}x';
    return '$moduleId @ $zoomStr';
  }

  /// Checks if this entry represents the same location as another.
  ///
  /// Two entries are at the same location if they have the same
  /// module, view state, and parameters.
  bool isSameLocation(HistoryEntry other) {
    return isSameHistoryLocation(
      moduleId: moduleId,
      view: view,
      params: params,
      otherModuleId: other.moduleId,
      otherView: other.view,
      otherParams: other.params,
    );
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is HistoryEntry && other.id == id;
  }

  @override
  int get hashCode => id.hashCode;
}

import 'dart:async' show Timer, unawaited;
import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/features/history/history_favorites.dart';
import 'package:flutter_fractals/features/history/history_location.dart';
import 'package:flutter_fractals/features/history/history_window.dart';

/// Manages exploration history with back/forward navigation and favorites.
///
/// [HistoryProvider] tracks the user's journey through fractal space,
/// allowing them to:
/// - Navigate back to previously visited locations
/// - Navigate forward after going back
/// - Save favorite spots with custom names
/// - View and jump to any point in history
///
/// History is automatically persisted to local storage.
///
/// {@category State Management}
///
/// Example usage:
/// ```dart
/// final history = HistoryProvider(store: historyStore);
///
/// // Record current location
/// history.recordLocation(
///   moduleId: 'mandelbrot',
///   view: controller.view,
///   params: controller.params,
/// );
///
/// // Navigate back
/// if (history.canGoBack) {
///   final entry = history.goBack();
///   // Apply entry to controller
/// }
/// ```
class HistoryProvider extends ChangeNotifier {
  final HistoryStore _store;

  /// All recorded history entries (oldest first).
  List<HistoryEntry> _history = [];

  /// Current position in history (index into _history).
  /// -1 means no history, 0+ is the index.
  int _currentIndex = -1;

  /// User's saved favorite locations.
  List<HistoryEntry> _favorites = [];

  /// Debounce timer to avoid recording too many entries during quick navigation.
  Timer? _debounceTimer;
  static const Duration _debounceDelay = Duration(milliseconds: 500);

  /// Last recorded state to detect meaningful changes.
  HistoryEntry? _lastRecorded;

  /// Creates a new [HistoryProvider].
  HistoryProvider({required HistoryStore store}) : _store = store {
    _loadFromStorage();
  }

  /// Whether navigation to a previous location is possible.
  bool get canGoBack => _currentIndex > 0;

  /// Whether navigation to a later location is possible.
  ///
  /// Only available after going back.
  bool get canGoForward => _currentIndex < _history.length - 1;

  /// The current history entry, if any.
  HistoryEntry? get currentEntry =>
      _currentIndex >= 0 && _currentIndex < _history.length
          ? _history[_currentIndex]
          : null;

  /// All history entries (oldest first).
  List<HistoryEntry> get history => List.unmodifiable(_history);

  /// Number of entries in history.
  int get historyCount => _history.length;

  /// Current position in history (1-indexed for display).
  int get currentPosition => _currentIndex + 1;

  /// All saved favorites.
  List<HistoryEntry> get favorites => List.unmodifiable(_favorites);

  /// Number of saved favorites.
  int get favoritesCount => _favorites.length;

  void _loadFromStorage() {
    final restored = HistoryRestorePolicy.restore(
      history: _store.loadHistory(),
      favorites: _store.loadFavorites(),
      maxHistoryEntries: HistoryStore.maxHistoryEntries,
      maxFavoriteEntries: HistoryStore.maxFavoriteEntries,
    );
    _history = restored.history;
    _favorites = restored.favorites;
    _currentIndex = restored.currentIndex;
    _lastRecorded = restored.currentEntry;
  }

  /// Records the current location in history.
  ///
  /// If the user has gone back and then makes a change,
  /// forward history is discarded (like a browser).
  ///
  /// Debounces rapid changes to avoid cluttering history
  /// with intermediate positions during smooth navigation.
  void recordLocation({
    required String moduleId,
    required FractalViewState view,
    required Map<String, Object> params,
  }) {
    final viewSnapshot = snapshotHistoryView(view);
    final paramsSnapshot = snapshotHistoryParams(params);

    _debounceTimer?.cancel();
    _debounceTimer = Timer(_debounceDelay, () {
      _doRecordLocation(moduleId, viewSnapshot, paramsSnapshot);
    });
  }

  void _doRecordLocation(
    String moduleId,
    FractalViewState view,
    Map<String, Object> params,
  ) {
    final entry = HistoryEntry.fromState(
      moduleId: moduleId,
      view: view,
      params: params,
    );

    // Skip if essentially the same location as the last entry
    if (_lastRecorded != null && _lastRecorded!.isSameLocation(entry)) {
      return;
    }

    final window = HistoryWindowPolicy.append(
      entries: _history,
      currentIndex: _currentIndex,
      entry: entry,
      maxEntries: HistoryStore.maxHistoryEntries,
    );
    _history = window.entries;
    _currentIndex = window.currentIndex;
    _lastRecorded = entry;

    unawaited(_store.saveHistory(_history));
    notifyListeners();
  }

  /// Navigates back to the previous location in history.
  ///
  /// Returns the entry to navigate to, or null if [canGoBack] is false.
  HistoryEntry? goBack() {
    if (!canGoBack) return null;
    return jumpToIndex(_currentIndex - 1);
  }

  /// Navigates forward to the next location in history.
  ///
  /// Returns the entry to navigate to, or null if [canGoForward] is false.
  HistoryEntry? goForward() {
    if (!canGoForward) return null;
    return jumpToIndex(_currentIndex + 1);
  }

  /// Jumps to a specific entry in history by index.
  HistoryEntry? jumpToIndex(int index) {
    if (index < 0 || index >= _history.length) return null;
    _selectHistoryIndex(index);
    notifyListeners();
    return _history[_currentIndex];
  }

  void _selectHistoryIndex(int index) {
    assert(index >= 0 && index < _history.length);
    // A debounced record captures pre-navigation controller state. If it fires
    // after an explicit history jump, it can silently truncate forward history
    // and move the current entry away from the user's selected replay point.
    cancelPendingRecord();
    _currentIndex = index;
    _lastRecorded = _history[index];
  }

  /// Jumps to a specific entry in history by ID.
  HistoryEntry? jumpToEntry(String entryId) {
    final index = _history.indexWhere((e) => e.id == entryId);
    if (index < 0) return null;
    return jumpToIndex(index);
  }

  /// Saves the current location as a favorite.
  ///
  /// Creates a named copy of the current history entry.
  Future<void> saveCurrentAsFavorite(String name) async {
    if (currentEntry == null) return;

    final favorite = currentEntry!.copyWith(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      name: name,
      visitedAt: DateTime.now(),
    );

    _favorites = HistoryFavoritesPolicy.append(
      favorites: _favorites,
      favorite: favorite,
      maxFavorites: HistoryStore.maxFavoriteEntries,
    );
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Saves a specific entry as a favorite.
  Future<void> saveAsFavorite(HistoryEntry entry, String name) async {
    final favorite = entry.copyWith(
      id: DateTime.now().microsecondsSinceEpoch.toString(),
      name: name,
      visitedAt: DateTime.now(),
    );

    _favorites = HistoryFavoritesPolicy.append(
      favorites: _favorites,
      favorite: favorite,
      maxFavorites: HistoryStore.maxFavoriteEntries,
    );
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Removes a favorite by ID.
  Future<void> removeFavorite(String favoriteId) async {
    _favorites.removeWhere((f) => f.id == favoriteId);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Renames a favorite.
  Future<void> renameFavorite(String favoriteId, String newName) async {
    final index = _favorites.indexWhere((f) => f.id == favoriteId);
    if (index < 0) return;

    _favorites[index] = _favorites[index].copyWith(name: newName);
    await _store.saveFavorites(_favorites);
    notifyListeners();
  }

  /// Checks if the current location is saved as a favorite.
  bool isCurrentFavorite() {
    if (currentEntry == null) return false;
    return _favorites.any((f) => f.isSameLocation(currentEntry!));
  }

  void _clearInMemoryHistory() {
    cancelPendingRecord();
    _history.clear();
    _currentIndex = -1;
    _lastRecorded = null;
  }

  /// Clears all history.
  Future<void> clearHistory() async {
    _clearInMemoryHistory();
    await _store.clearHistory();
    notifyListeners();
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    _favorites.clear();
    await _store.clearFavorites();
    notifyListeners();
  }

  /// Applies a history entry to a controller-like object.
  ///
  /// Kept intentionally structural so history navigation tests do not depend on
  /// renderer module registration. The controller is expected to expose
  /// `updateParam`, `updateZoom`, `updatePan`, and `updateRotation` methods.
  void applyToController(HistoryEntry entry, Object controller) {
    final target = controller as dynamic;

    // Update parameters
    for (final paramEntry in entry.params.entries) {
      try {
        target.updateParam(paramEntry.key, paramEntry.value);
      } catch (_) {
        // Parameter may not exist in current module
      }
    }

    // Update view state
    target.updateZoom(entry.view.zoom);
    target.updatePan(entry.view.pan);
    target.updateRotation(entry.view.rotation);
  }

  /// Cancels any pending debounced history record.
  void cancelPendingRecord() {
    _debounceTimer?.cancel();
    _debounceTimer = null;
  }

  @override
  void dispose() {
    cancelPendingRecord();
    super.dispose();
  }
}

import 'dart:convert';

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:vector_math/vector_math.dart';

HistoryEntry _entry({
  String moduleId = 'mandelbrot',
  double zoom = 1,
  Map<String, Object> params = const <String, Object>{},
}) {
  return HistoryEntry(
    id: 'entry-$moduleId-$zoom-${params.length}',
    moduleId: moduleId,
    view: FractalViewState(
      pan: Vector2.zero(),
      zoom: zoom,
      rotation: Vector3.zero(),
    ),
    params: params,
    visitedAt: DateTime.utc(2024),
  );
}

void main() {
  group('HistoryEntry location identity', () {
    test('treats matching module, view, and params as the same location', () {
      final first = _entry(params: {'iterations': 100, 'bailout': 4.0});
      final second = _entry(params: {'bailout': 4.0, 'iterations': 100});

      expect(first.isSameLocation(second), isTrue);
    });

    test('treats parameter changes as a different location', () {
      final first = _entry(params: {'iterations': 100});
      final second = _entry(params: {'iterations': 250});

      expect(first.isSameLocation(second), isFalse);
    });

    test('treats JSON-like list parameter values as replayable values', () {
      final first = _entry(params: {
        'paletteStops': [0.0, 0.5, 1.0],
      });
      final second = _entry(params: {
        'paletteStops': [0.0, 0.5, 1.0],
      });

      expect(first.isSameLocation(second), isTrue);
    });

    test('treats view changes as a different location', () {
      final first = _entry(zoom: 1);
      final second = _entry(zoom: 2);

      expect(first.isSameLocation(second), isFalse);
    });

    test('snapshots mutable view vectors and params when created from state',
        () {
      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;

      expect(entry.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });

    test('constructor snapshots mutable view and freezes nested params', () {
      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final paletteStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
      ];
      final params = <String, Object>{'paletteStops': paletteStops};

      final entry = HistoryEntry(
        id: 'entry',
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
        visitedAt: DateTime.utc(2024),
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      (paletteStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((paletteStops[1] as Map<String, Object?>)['rgb'] as List<Object?>)[0] =
          255;
      paletteStops.add(1.0);

      expect(entry.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
        ],
      });
      expect(
        () => entry.params['paletteStops'] = <Object?>[],
        throwsUnsupportedError,
      );
      expect(
        () => (entry.params['paletteStops'] as List<Object?>).add(1.0),
        throwsUnsupportedError,
      );
      expect(
        () => ((entry.params['paletteStops'] as List<Object?>)[1]
            as Map<String, Object?>)['position'] = 0.75,
        throwsUnsupportedError,
      );
    });

    test('serializes nested map parameter keys as JSON object keys', () {
      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2.zero(),
          zoom: 6,
          rotation: Vector3.zero(),
        ),
        params: <String, Object>{
          'metadata': <Object, Object>{1: 'one'},
        },
      );

      final encoded = jsonEncode(entry.toJson());
      final decoded = jsonDecode(encoded) as Map<String, Object?>;
      final restored = HistoryEntry.fromJson(decoded);

      expect(restored.params, {
        'metadata': {'1': 'one'},
      });
    });

    test('deep-snapshots nested JSON-like params when created from state', () {
      final paletteStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
        1.0,
      ];
      final params = <String, Object>{'paletteStops': paletteStops};

      final entry = HistoryEntry.fromState(
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2.zero(),
          zoom: 6,
          rotation: Vector3.zero(),
        ),
        params: params,
      );

      (paletteStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((paletteStops[1] as Map<String, Object?>)['rgb'] as List<Object?>)[0] =
          255;
      paletteStops.add(2.0);

      expect(entry.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
          1.0,
        ],
      });
    });

    test('snapshots replacement view and params when copied', () {
      final replacementPan = Vector2(1, 2);
      final replacementRotation = Vector3(3, 4, 5);
      final replacementStops = <Object?>[
        0.0,
        <String, Object?>{
          'position': 0.5,
          'rgb': <Object?>[32, 64, 128],
        },
      ];
      final replacementParams = <String, Object>{
        'paletteStops': replacementStops,
      };

      final copied = _entry().copyWith(
        view: FractalViewState(
          pan: replacementPan,
          zoom: 6,
          rotation: replacementRotation,
        ),
        params: replacementParams,
      );

      replacementPan.setValues(7, 8);
      replacementRotation.setValues(9, 10, 11);
      (replacementStops[1] as Map<String, Object?>)['position'] = 0.75;
      ((replacementStops[1] as Map<String, Object?>)['rgb']
          as List<Object?>)[0] = 255;
      replacementStops.add(1.0);

      expect(copied.view.pan.x, 1);
      expect(copied.view.pan.y, 2);
      expect(copied.view.rotation.x, 3);
      expect(copied.view.rotation.y, 4);
      expect(copied.view.rotation.z, 5);
      expect(copied.params, {
        'paletteStops': [
          0.0,
          {
            'position': 0.5,
            'rgb': [32, 64, 128],
          },
        ],
      });
    });
  });
}

import 'package:vector_math/vector_math.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';

/// Creates an immutable-by-convention history snapshot of a mutable view state.
///
/// [FractalViewState] stores mutable vector_math objects, so history must clone
/// those vectors at the record boundary to keep debounced writes replayable.
FractalViewState snapshotHistoryView(FractalViewState view) {
  return FractalViewState(
    pan: Vector2.copy(view.pan),
    zoom: view.zoom,
    rotation: Vector3.copy(view.rotation),
  );
}

/// Creates a deep JSON-like snapshot of parameters at the record boundary.
Map<String, Object> snapshotHistoryParams(Map<String, Object> params) {
  return Map<String, Object>.unmodifiable({
    for (final entry in params.entries)
      entry.key: snapshotHistoryParamValue(entry.value),
  });
}

/// Deep-copies JSON-like parameter values so history replay is not affected by
/// later mutations of nested list/map values owned by controllers or widgets.
///
/// Nested map keys are normalized to strings because history entries are
/// persisted as JSON objects. Without this, a controller-owned metadata map
/// with enum/int keys can make the whole history save fail during jsonEncode.
/// Returned collections are unmodifiable so public [HistoryEntry] reads cannot
/// mutate stored history without going through provider methods.
Object snapshotHistoryParamValue(Object value) {
  if (value is List) {
    return List<Object?>.unmodifiable([
      for (final item in value)
        item is Object ? snapshotHistoryParamValue(item) : item,
    ]);
  }

  if (value is Map) {
    return Map<String, Object?>.unmodifiable({
      for (final entry in value.entries)
        entry.key.toString(): entry.value is Object
            ? snapshotHistoryParamValue(entry.value as Object)
            : entry.value,
    });
  }

  return value;
}

/// Pure location-equivalence contract for history de-duplication.
///
/// A history location is the restorable fractal state: module, view, and
/// parameters. Metadata such as entry id, favorite name, and timestamp is not
/// part of location identity.
bool isSameHistoryLocation({
  required String moduleId,
  required FractalViewState view,
  required Map<String, Object> params,
  required String otherModuleId,
  required FractalViewState otherView,
  required Map<String, Object> otherParams,
}) {
  if (moduleId != otherModuleId) {
    return false;
  }
  if (view.zoom != otherView.zoom) {
    return false;
  }
  if (view.pan.x != otherView.pan.x || view.pan.y != otherView.pan.y) {
    return false;
  }
  if (view.rotation.x != otherView.rotation.x ||
      view.rotation.y != otherView.rotation.y ||
      view.rotation.z != otherView.rotation.z) {
    return false;
  }
  return haveSameHistoryParams(params, otherParams);
}

/// Compares history parameter snapshots without relying on map iteration order.
bool haveSameHistoryParams(
  Map<String, Object> params,
  Map<String, Object> otherParams,
) {
  if (params.length != otherParams.length) {
    return false;
  }

  for (final entry in params.entries) {
    if (!otherParams.containsKey(entry.key)) {
      return false;
    }
    if (!areSameHistoryParamValue(entry.value, otherParams[entry.key])) {
      return false;
    }
  }

  return true;
}

/// Compares JSON-like history parameter values by value rather than identity.
///
/// Persisted params can contain nested lists/maps after JSON decode. Dart's
/// collection equality is identity-based, which would make two replayed
/// locations look different even when their serialized parameter values match.
bool areSameHistoryParamValue(Object? value, Object? otherValue) {
  if (identical(value, otherValue)) return true;

  if (value is List && otherValue is List) {
    if (value.length != otherValue.length) return false;
    for (var i = 0; i < value.length; i++) {
      if (!areSameHistoryParamValue(
          value[i] as Object?, otherValue[i] as Object?)) {
        return false;
      }
    }
    return true;
  }

  if (value is Map && otherValue is Map) {
    if (value.length != otherValue.length) return false;
    for (final entry in value.entries) {
      if (!otherValue.containsKey(entry.key)) return false;
      if (!areSameHistoryParamValue(
        entry.value as Object?,
        otherValue[entry.key] as Object?,
      )) {
        return false;
      }
    }
    return true;
  }

  return value == otherValue;
}

import 'package:flutter_fractals/features/history/history_entry.dart';

/// Pure favorite-list append policy shared by provider mutations.
///
/// Persistence caps favorites to keep local storage bounded. The provider must
/// apply the same cap before notifying listeners so in-memory UI state and the
/// next app launch agree about which favorites still exist.
class HistoryFavoritesPolicy {
  const HistoryFavoritesPolicy._();

  static List<HistoryEntry> append({
    required List<HistoryEntry> favorites,
    required HistoryEntry favorite,
    required int maxFavorites,
  }) {
    assert(maxFavorites > 0);

    final nextFavorites = List<HistoryEntry>.of(favorites)..add(favorite);
    if (nextFavorites.length > maxFavorites) {
      nextFavorites.removeRange(0, nextFavorites.length - maxFavorites);
    }
    return nextFavorites;
  }
}

import 'package:flutter_fractals/features/history/history_entry.dart';

/// Result of applying a history-list mutation.
class HistoryWindow {
  /// History entries in display order (oldest first).
  final List<HistoryEntry> entries;

  /// Current selected index into [entries], or -1 when empty.
  final int currentIndex;

  const HistoryWindow({
    required this.entries,
    required this.currentIndex,
  });
}

/// Restored history and favorite lists after applying in-memory caps.
class HistoryRestoreSnapshot {
  final List<HistoryEntry> history;
  final int currentIndex;
  final List<HistoryEntry> favorites;

  const HistoryRestoreSnapshot({
    required this.history,
    required this.currentIndex,
    required this.favorites,
  });

  HistoryEntry? get currentEntry =>
      currentIndex >= 0 && currentIndex < history.length
          ? history[currentIndex]
          : null;
}

/// Pure storage-restore policy shared by provider boot and tests.
///
/// Storage writes are capped, but older/corrupted preferences can still contain
/// too many entries. Normalize immediately so first-frame UI state matches the
/// same bounded contract as persisted writes.
class HistoryRestorePolicy {
  const HistoryRestorePolicy._();

  static HistoryRestoreSnapshot restore({
    required List<HistoryEntry> history,
    required List<HistoryEntry> favorites,
    required int maxHistoryEntries,
    required int maxFavoriteEntries,
  }) {
    assert(maxHistoryEntries > 0);
    assert(maxFavoriteEntries > 0);

    final restoredHistory = _mostRecent(history, maxHistoryEntries);
    return HistoryRestoreSnapshot(
      history: restoredHistory,
      currentIndex: restoredHistory.isEmpty ? -1 : restoredHistory.length - 1,
      favorites: _mostRecent(favorites, maxFavoriteEntries),
    );
  }

  static List<HistoryEntry> _mostRecent(
    List<HistoryEntry> entries,
    int maxEntries,
  ) {
    if (entries.length <= maxEntries) return List<HistoryEntry>.of(entries);
    return entries.sublist(entries.length - maxEntries);
  }
}

/// Pure history append policy shared by recording and tests.
///
/// The in-memory provider must enforce the same maximum depth as persistence;
/// otherwise entries silently disappear only after app restart.
class HistoryWindowPolicy {
  const HistoryWindowPolicy._();

  static HistoryWindow append({
    required List<HistoryEntry> entries,
    required int currentIndex,
    required HistoryEntry entry,
    required int maxEntries,
  }) {
    assert(maxEntries > 0);

    final nextEntries = currentIndex >= 0 && currentIndex < entries.length - 1
        ? entries.sublist(0, currentIndex + 1)
        : List<HistoryEntry>.of(entries);

    nextEntries.add(entry);

    if (nextEntries.length > maxEntries) {
      nextEntries.removeRange(0, nextEntries.length - maxEntries);
    }

    return HistoryWindow(
      entries: nextEntries,
      currentIndex: nextEntries.length - 1,
    );
  }
}

import 'dart:convert';

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/services/history_store.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';
import 'package:flutter_fractals/features/history/history_provider.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:vector_math/vector_math.dart';

FractalViewState _view(double zoom) {
  return FractalViewState(
    pan: Vector2.zero(),
    zoom: zoom,
    rotation: Vector3.zero(),
  );
}

Map<String, Object?> _entryJson(double zoom) {
  return HistoryEntry.fromState(
    moduleId: 'mandelbrot',
    view: _view(zoom),
    params: const <String, Object>{'iterations': 100},
  ).toJson();
}

Future<void> _recordAndFlush(
  WidgetTester tester,
  HistoryProvider provider, {
  required double zoom,
}) async {
  provider.recordLocation(
    moduleId: 'mandelbrot',
    view: _view(zoom),
    params: const <String, Object>{'iterations': 100},
  );
  await tester.pump(const Duration(milliseconds: 501));
}

void main() {
  group('HistoryProvider navigation recording', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    testWidgets(
        'replaying the current back entry does not truncate forward history',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);
      await _recordAndFlush(tester, provider, zoom: 2);
      await _recordAndFlush(tester, provider, zoom: 3);

      final restored = provider.goBack();
      expect(restored, isNotNull);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);

      await _recordAndFlush(tester, provider, zoom: 2);

      expect(provider.historyCount, 3);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);
      expect(provider.currentEntry, same(restored));
    });

    testWidgets('history navigation cancels pending pre-navigation records',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);
      await _recordAndFlush(tester, provider, zoom: 2);

      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: _view(3),
        params: const <String, Object>{'iterations': 100},
      );

      final restored = provider.goBack();
      expect(restored, isNotNull);
      expect(restored!.view.zoom, 1);
      expect(provider.currentPosition, 1);
      expect(provider.canGoForward, isTrue);

      await tester.pump(const Duration(milliseconds: 501));

      expect(provider.historyCount, 2);
      expect(provider.currentPosition, 1);
      expect(provider.currentEntry, same(restored));
      expect(provider.canGoForward, isTrue);
      expect(provider.history.map((entry) => entry.view.zoom), [1, 2]);
    });

    testWidgets('records the state passed to the debounced record call',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;
      await tester.pump(const Duration(milliseconds: 501));

      final entry = provider.currentEntry;
      expect(entry, isNotNull);
      expect(entry!.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });

    testWidgets('keeps in-memory history capped to the persisted max depth',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++) {
        await _recordAndFlush(tester, provider, zoom: i + 1.0);
      }

      expect(provider.historyCount, HistoryStore.maxHistoryEntries);
      expect(provider.currentPosition, HistoryStore.maxHistoryEntries);
      expect(provider.history.first.view.zoom, 3.0);
      expect(provider.currentEntry!.view.zoom, 102.0);
    });

    testWidgets('keeps in-memory favorites capped to persisted max depth',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);

      for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++) {
        await provider.saveCurrentAsFavorite('favorite $i');
      }

      expect(provider.favoritesCount, HistoryStore.maxFavoriteEntries);
      expect(provider.favorites.first.name, 'favorite 2');
      expect(provider.favorites.last.name, 'favorite 501');
      expect(store.loadFavorites().length, HistoryStore.maxFavoriteEntries);
    });

    testWidgets('restored history and favorites are capped before display',
        (tester) async {
      SharedPreferences.setMockInitialValues({
        'exploration_history': jsonEncode([
          for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++)
            _entryJson(i + 1.0),
        ]),
        'exploration_favorites': jsonEncode([
          for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++)
            _entryJson(i + 1.0),
        ]),
      });

      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      expect(provider.historyCount, HistoryStore.maxHistoryEntries);
      expect(provider.currentPosition, HistoryStore.maxHistoryEntries);
      expect(provider.history.first.view.zoom, 3.0);
      expect(provider.currentEntry!.view.zoom, 102.0);
      expect(provider.favoritesCount, HistoryStore.maxFavoriteEntries);
      expect(provider.favorites.first.view.zoom, 3.0);
      expect(provider.favorites.last.view.zoom, 502.0);
    });

    testWidgets('clearHistory cancels pending debounced records',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: _view(6),
        params: const <String, Object>{'iterations': 100},
      );
      await provider.clearHistory();
      await tester.pump(const Duration(milliseconds: 501));

      expect(provider.historyCount, 0);
      expect(provider.currentEntry, isNull);
      expect(store.loadHistory(), isEmpty);
    });
  });
}

